query:
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '16.', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.' FROM position_categories WHERE positionId = 8 AND name = 'Kalite Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '17.', 'Çalışma ortamında iyi ilişkiler kurar ve korur.' FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '18.', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.' FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '19.', 'Takım ruhuna uyumlu yaklaşımda bulunur.' FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '20.', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.' FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '21.', 'Müşteri ihtiyaçlarını anlar ve bu ihtiyaçları doğru şekilde tanımlar.' FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '22.', 'Müşteri sorunlarına hızlı ve etkili çözümler bulur.' FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '23.', 'Müşterisine karşı anlayışlı, sabırlı ve saygılı bir iletişim tarzı benimser.' FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '24.', 'Müşteri memnuniyeti artırmaya yönelik çalışmalara katkıda bulunur.' FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '25.', 'Yaptığı işin sonuçlarının kurumun beklediği ticari sonuçlar ile paralel olmasını gözetir.' FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '26.', 'Uygun durumlarda, satış fırsatlarını geliştirecek alternatif yaklaşımlar tavsiye eder.' FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '27.', 'Kurumun müşteri sayısını geliştirmeye yönelik çalışmalarda bulunur.' FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '28.', 'Görevlerini sahip olduğu zamanı dikkate alarak gereken sürede tamamlar.' FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '29.', 'Birden fazla işe odaklanarak bunları eş zamanlı yürütebilir.' FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '30.', 'Planlama ile ilgili öncelikleri saptar, yetki sınırları içinde doğru sıralamayı gerçekleştirir.' FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '1.', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder.' FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '2.', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.' FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '3.', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.' FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '4.', 'İnsan Kaynakları tarafından yayınlanan Şirket Davranış Talimatına uygun hareket eder.' FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '5.', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.' FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '6', 'Müşterilere karşı güleryüzlü ve naziktir.' FROM position_categories WHERE positionId = 8 AND name = 'Servis' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '7', 'Güleryüzlü bir şekilde karşılama ve uğurlama yapar.' FROM position_categories WHERE positionId = 8 AND name = 'Servis' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '8', 'Müşteri siparişlerini standartlara uygun ve doğru bir şekilde alır.' FROM position_categories WHERE positionId = 8 AND name = 'Servis' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '9', 'Müşterilere önerili satış yapar.' FROM position_categories WHERE positionId = 8 AND name = 'Servis' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '10', 'Ürünlerle ve içerikleri ile ilgili bilgilidir.' FROM position_categories WHERE positionId = 8 AND name = 'Servis' LIMIT 1;

